function wa(phone, name) {
  const msg = encodeURIComponent("שלום " + name + ", כאן ערדית מ-Multibrawn 👋\nמצאתי עבורכם משהו מתאים!\n052-3983394");
  const p = phone.replace(/\D/g,"");
  const intl = p.startsWith("0") ? "972"+p.slice(1) : p;
  window.open("https://wa.me/"+intl+"?text="+msg, "_blank");
}

function mailTo(email, type) {
  const subj = type === "hotel" ? "שיתוף פעולה — שבתות חתן | Multibrawn" : "נמצא נכס מתאים — Multibrawn";
  const body = type === "hotel"
    ? "שלום,\n\nכאן ערדית בראון מ-Multibrawn.\nיש לי לקוחות מתאימים — נשמח לשתף פעולה.\n\nערדית | 052-3983394"
    : "שלום,\n\nכאן ערדית מ-Multibrawn.\nמצאתי עבורכם נכס שמתאים!\n\nערדית | 052-3983394";
  window.open("mailto:"+email+"?subject="+encodeURIComponent(subj)+"&body="+encodeURIComponent(body), "_blank");
}

